 Monzo.potDeposit.setAmount: {
   amount: (Strava.newActivityByYou.DistanceMeters / 10) * 0.01
 }
};

// Define the filter function
const filterFunction = (activity) => {
 // Check if the activity is a running or cycling activity
 if (activity.ActivityType === 'Running' || activity.ActivityType === 'Cycling') {
   // Check if the activity is over 10 meters
   if (activity.DistanceMeters > 10) {
     // Deposit the amount into the savings pot
     Monzo.potDeposit.setAmount(activity.DistanceMeters / 10 * 0.01);
   }
 }
};

// Apply the filter function to the trigger conditions
const filteredTriggerConditions = filterFunction(triggerConditions);

// Apply the action behavior to the filtered trigger conditions
const filteredActionBehavior = filterFunction(actionBehavior);

// Return the filtered trigger conditions and action behavior
return {
 triggerConditions: filteredTriggerConditions,
 actionBehavior: filteredActionBehavior
};
