 const isDartDelay = Dart.newDartRiderAlert.EntryTitle.includes("DART Delay");
 const isCommutingHour = currentTime.hour() >= 17 && currentTime.hour() <= 19;
 const isGmailAccount = Dart.newDartRiderAlert.EntryUrl.includes("gmail.com");
 const isDelayAlert = isDartDelay && isCommutingHour && isWeekday;

 if (isDelayAlert) {
