 // Check if the tweet is a retweet
 if (tweet.startsWith("RT")) {
   // Strip the retweet prefix and remove any mentions
   const strippedTweet = tweet.replace(/^RT\s+/, "").replace(/@\w+/g, "");

   // Check the character count of the remaining text
   if (strippedTweet.length <= 140) {
     // Append a random hashtag from a predetermined list
     const hashtags = ["#MovimientoCiudadano", "#RepúblicaConstitucional", "#Política", "#Actualidad"];
     const randomHashtag = hashtags[Math.floor(Math.random() * hashtags.length)];
     const tweetWithHashtag = `${strippedTweet} ${randomHashtag}`;

     // Check if the tweet exceeds the character limit
     if (tweetWithHashtag.length <= 140) {
       // Post a new tweet to the user's account
       Twitter.postNewTweet.setTweet(tweetWithHashtag);
     } else {
       // Skip the tweet if it exceeds the character limit
       Twitter.postNewTweet.skip();
     }
   } else {
     // Skip the tweet if it exceeds the character limit
     Twitter.postNewTweet.skip();
