   // Check if the tweet contains the word "Ethereum"
   condition: Twitter.newTweetByUser.Text.includes("Ethereum"),
   // Check if the tweet is from the user "CryptoGuru"
   condition: Twitter.newTweetByUser.UserName === "CryptoGuru",
   // Check if the tweet is within the last 24 hours
   condition: Twitter.newTweetByUser.CreatedAt.isAfter(
     Meta.currentUserTime.subtract(1, "days")
   ),
 },
];

// Define the action behavior
const actionBehavior = {
 // Set the subject of the email
 subject: "Ethereum Price Update",
 // Set the body of the email
 body: `
   <p>A new tweet from @CryptoGuru has been posted about Ethereum!</p>
   <p>Here's the tweet:</p>
   <blockquote>${Twitter.newTweetByUser.TweetEmbedCode}</blockquote>
   <p>The price change is ${Twitter.newTweetByUser.PriceChange}%.</p>
 `,
};

// Define the filter function
const filterFunction = (tweet) => {
 // Check if the tweet meets the trigger conditions
 if (triggerConditions.every((condition) => condition(tweet))) {
   // Check if the price change is more than ±10%
   if (Math.abs(tweet.PriceChange) > 10) {
     // Send the email
     Email.sendMeEmail.setSubject(actionBehavior.subject);
     Email.sendMeEmail.setBody(actionBehavior.body);
     Email.sendMeEmail.send();
   } else {
     // Skip the email
     Email.sendMeEmail.skip();
   }
 }
};

// Apply the filter function to the tweet stream
Twitter.newTweetByUser.subscribe(filterFunction);
```
This code defines a filter function that checks if a tweet meets the trigger conditions (i.e., it contains the word "Ethereum" and is from the user "CryptoGuru" and was posted within the last 24 hours). If the tweet meets the trigger conditions, the filter function checks if the price change is more than ±10%. If it is, the filter function sends an email with the subject "Ethereum Price Update" and the body of the email containing the tweet and the price change. If the price change is less than ±10%, the filter function skips sending the email.

The code uses the `Meta.currentUserTime` accessor to access the current date and time, and the `Math.abs` function to calculate the absolute value of the price change. The `Twitter.newTweetByUser.subscribe` method is used to apply the filter function to the tweet stream.

