const {
 Feed,
 Slack,
 Meta
} = require('./accessors');

const {
 setMessage,
 setTitle,
 setTitleUrl,
 setImageUrl,
 skip
} = require('./actions');

const {
 EntryTitle,
 EntryUrl,
 EntryAuthor,
 EntryContent,
 EntryImageUrl,
 EntryPublished,
 FeedTitle,
 FeedUrl
} = Feed.newFeedItem;

const {
 currentUserTime
} = Meta;

const isNewEvent = (entry) => {
 const published = currentUserTime(entry.EntryPublished);
 const now = currentUserTime();
 return published.isAfter(now);
};

const isEventInTokyoKanagawaYokohama = (entry) => {
 const content = entry.EntryContent;
 return content.includes('Tokyo') || content.includes('Kanagawa') || content.includes('Yokohama');
};

const isEventLocationInTokyoKanagawaYokohama = (entry) => {
 const location = entry.EntryLocation;
 return location.includes('Tokyo') || location.includes('Kanagawa') || location.includes('Yokohama');
};

const notify = (entry) => {
 const message = `New event: ${entry.EntryTitle}
 ${entry.EntryUrl}
 ${entry.EntryImageUrl}`;
 const title = entry.EntryTitle;
 const titleUrl = entry.EntryUrl;
 const imageUrl = entry.EntryImageUrl;
 Slack.postToChannel.setMessage(message);
 Slack.postToChannel.setTitle(title);
 Slack.postToChannel.setTitleUrl(titleUrl);
 Slack.postToChannel.setImageUrl(imageUrl);
};

const skipNotify = (entry) => {
 Slack.postToChannel.skip();
};

const filter = (entry) => {
 if (isNewEvent(entry) && isEventInTokyoKanagawaYokohama(entry)) {
   if (isEventLocationInTokyoKanagawaYokohama(entry)) {
     notify(entry);
   } else {
     skipNotify(entry);
   }
 }
};

module.exports = {
 filter
};
