 const currentTime = Meta.currentUserTime;
 const tweetTime = newTweetByUser.CreatedAt;
 const tweetLink = newTweetByUser.LinkToTweet;
 const tweetEmbedCode = newTweetByUser.TweetEmbedCode;
 const tweetText = newTweetByUser.Text;
 const tweetUser = newTweetByUser.UserName;

 // Check if the tweet is created between 8 AM and 10 PM
 if (currentTime.hour() >= 8 && currentTime.hour() <= 22) {
   // Send a high-priority notification
   IfNotifications.sendNotification.setMessage(`${tweetUser} tweeted: ${tweetText}`);
   IfNotifications.sendNotification.setHighPriority(true);
 } else {
   // Skip the notification if the tweet is created outside of the 8 AM to 10 PM time frame
   IfNotifications.sendNotification.skip();
 }

 // Check if the tweet contains a link
 if (tweetLink) {
   // Save the link to the 'Saved For Later' queue if it hasn't been seen before
   Feedly.createNewEntryFeedly.setUrl(tweetLink);
 } else {
   // Skip the action if the tweet doesn't contain a link
   Feedly.createNewEntryFeedly.skip();
 }

 return true;
}
