// Trigger-action rule for Twitter notifications

// Define the trigger conditions
const triggerConditions = [
 {
   // Tweet must be created by the specified user
   userName: 'MyFavoriteTwitterUser',
 },
 {
   // Tweet must contain a specific article link
   linkToTweet: 'https://example.com/article',
 },
 {
   // Tweet must be created between 8 AM and 10 PM
   createdAt: {
     hour: {
       $gte: 8,
       $lte: 22,
     },
   },
 },
];

// Define the action behavior
const actionBehavior = {
 // Send a notification if the tweet is created between 8 AM and 10 PM
 sendNotification: {
   message: 'New tweet from MyFavoriteTwitterUser!',
   highPriority: true,
 },
 // Create a new entry in Feedly if the tweet contains a specific article link
 createNewEntryFeedly: {
   url: 'https://example.com/article',
 },
};

// Filter code to refine the trigger-action rule
const filterCode = {
 // Filter out tweets that do not meet the trigger conditions
 $filter: {
   $and: [
     {
       userName: 'MyFavoriteTwitterUser',
     },
     {
       linkToTweet: 'https://example.com/article',
     },
     {
       createdAt: {
         hour: {
           $gte: 8,
           $lte: 22,
         },
       },
     },
   ],
 },
 // Filter out tweets that are created outside of the 8 AM to 10 PM window
 $filter: {
   $and: [
     {
       createdAt: {
         hour: {
           $gte: 8,
           $lte: 22,
         },
       },
     },
   ],
 },
 // Filter out tweets that contain a specific article link that the user already knows about
 $filter: {
   $and: [
     {
       linkToTweet: 'https://example.com/article',
     },
     {
       createdAt: {
         hour: {
           $gte: 8,
           $lte: 22,
         },
       },
     },
   ],
 },
};

// Return the filtered trigger-action rule
return {
 triggerConditions,
 actionBehavior,
 filterCode,
};
