// Trigger-action rule: Notify me whenever @specificuser tweets during the day, but don’t send notifications late at night or save duplicate articles.

// Define the trigger conditions
const triggerConditions = [
 {
   // Tweet must be created by @specificuser
   condition: Twitter.newTweetByUser.UserName === 'specificuser',
   // Tweet must be created during the day (8 AM to 10 PM)
   condition: Twitter.newTweetByUser.CreatedAt.hour() >= 8 && Twitter.newTweetByUser.CreatedAt.hour() <= 22,
 },
 {
   // Tweet must be created by @specificuser
   condition: Twitter.newTweetByUser.UserName === 'specificuser',
   // Tweet must be created outside of the day (10 PM to 8 AM)
   condition: Twitter.newTweetByUser.CreatedAt.hour() < 8 || Twitter.newTweetByUser.CreatedAt.hour() > 22,
 },
 {
   // Tweet must be created by @specificuser
   condition: Twitter.newTweetByUser.UserName === 'specificuser',
   // Tweet must not be a duplicate
   condition: !Feedly.createNewEntryFeedly.isDuplicate(Twitter.newTweetByUser.LinkToTweet),
 },
];

// Define the action behavior
const actionBehavior = [
 {
   // Send a notification if the tweet is created during the day
   action: IfNotifications.sendNotification.setMessage(Twitter.newTweetByUser.Text),
   condition: Twitter.newTweetByUser.CreatedAt.hour() >= 8 && Twitter.newTweetByUser.CreatedAt.hour() <= 22,
 },
 {
   // Skip sending a notification if the tweet is created outside of the day
   action: IfNotifications.sendNotification.skip,
   condition: Twitter.newTweetByUser.CreatedAt.hour() < 8 || Twitter.newTweetByUser.CreatedAt.hour() > 22,
 },
 {
   // Save the tweet URL for later if the tweet is not a duplicate
   action: Feedly.createNewEntryFeedly.setUrl(Twitter.newTweetByUser.LinkToTweet),
   condition: !Feedly.createNewEntryFeedly.isDuplicate(Twitter.newTweetByUser.LinkToTweet),
 },
];

// Apply the trigger-action rule
const rule = new TriggerActionRule(triggerConditions, actionBehavior);
